const row = $input.first().json;

const slug = row.slug || (row.class || row.name || 'unknown')
  .toLowerCase().replace(/_/g, '-').replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');

function parsePrices(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { return []; } }
  return Array.isArray(raw) ? raw : [];
}

const uexPrices  = parsePrices(row.uex_prices);
const dp4kPrices = parsePrices(row.datap4k_prices);
const stats = (typeof row.stats === 'string') ? JSON.parse(row.stats || '{}') : (row.stats || {});

// Build natural language description
const sentences = [];
const catName = row.uex_category_name || row.type || 'component';
const sizeStr = row.size ? ' size ' + row.size : '';
const mfr     = row.manufacturer || null;
sentences.push(
  'The ' + row.name + ' is a' + sizeStr + ' ' + catName.toLowerCase()
  + (row.uex_category_section ? ' (' + row.uex_category_section + ')' : '')
  + (mfr ? ', manufactured by ' + mfr : '') + '.'
);

if (row.grade) sentences.push('It is grade ' + row.grade + '.');
if (row.sub_type) sentences.push('Subtype: ' + row.sub_type + '.');

// Stats sentence
const statParts = [];
const statLabels = {
  'hp': 'HP', 'regen-per-sec': 'regen/s',
  'speed-mms': 'QD speed (mm/s)', 'spool-sec': 'spool time (s)',
  'fuel': 'fuel capacity', 'q-fuel': 'Q-fuel capacity',
  'damage-per-shot': 'damage/shot', 'fire-rate-per-min': 'fire rate (RPM)',
  'ideal-range-m': 'ideal range (m)', 'damage': 'damage',
  'speed-mps': 'speed (m/s)'
};
const keySummary = ['hp','regen-per-sec','speed-mms','spool-sec','fuel','q-fuel',
                    'damage-per-shot','fire-rate-per-min','ideal-range-m','damage','speed-mps'];
for (const k of keySummary) {
  if (stats[k] !== undefined && stats[k] !== null && Number(stats[k]) > 0) {
    statParts.push(Number(stats[k]).toFixed(2).replace(/\.?0+$/, '') + ' ' + (statLabels[k] || k));
  }
}
if (statParts.length > 0) sentences.push('Key stats: ' + statParts.join(', ') + '.');

if (uexPrices.length > 0) {
  sentences.push('Available at ' + uexPrices.length + ' terminal' + (uexPrices.length > 1 ? 's' : '') + ' with live UEX pricing.');
} else if (dp4kPrices.length > 0) {
  sentences.push('Shop data from DataPack available (' + dp4kPrices.length + ' location' + (dp4kPrices.length > 1 ? 's' : '') + ').');
} else {
  sentences.push('No live purchase pricing currently available in UEX.');
}

const kb_text = sentences.join(' ');

// Hashing
function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hash16(str) { return fnv1a32Hex(str) + fnv1a32Hex(str + '|v2'); }
function stableStringify(val) {
  if (val === null || typeof val !== 'object') return JSON.stringify(val);
  if (Array.isArray(val)) return '[' + val.map(stableStringify).join(',') + ']';
  return '{' + Object.keys(val).sort().map(k => JSON.stringify(k) + ':' + stableStringify(val[k])).join(',') + '}';
}

const jsonkb = {
  entity_type: 'component',
  entity_slug: slug,
  name:         row.name,
  category:     catName,
  section:      row.uex_category_section || null,
  type:         row.type || null,
  sub_type:     row.sub_type || null,
  size:         row.size ? Number(row.size) : null,
  grade:        row.grade ? Number(row.grade) : null,
  manufacturer: mfr,
  stats:        stats,
  uex_id:       row.uex_id ? Number(row.uex_id) : null,
  uex_prices:   uexPrices,
  datap4k_prices: dp4kPrices,
  kb_text,
  provenance: {
    source: 'datap4k_components_norm',
    workflow: 'JSONKB - Components v1',
    content_hash: hash16(stableStringify({
      name: row.name, class: row.class, stats,
      uex_prices: uexPrices, datap4k_prices: dp4kPrices
    }))
  }
};

return [{
  json: {
    slug,
    jsonkb,
    jsonkb_file_path: 'jsonkb/component/' + slug + '.json'
  }
}];

const buildResult   = $('Build JSONKB').item.json;
const existingRow   = $input.first().json;
const currentHash   = buildResult.jsonkb && buildResult.jsonkb.provenance ? buildResult.jsonkb.provenance.content_hash : null;
const existingHash  = existingRow ? existingRow.content_hash : null;
const should_write  = !existingHash || existingHash !== currentHash;
return [{ json: { ...buildResult, should_write, existing_hash: existingHash } }];

const buildResult = $('Build JSONKB').item.json;
const slug        = (buildResult.slug || '').replace(/'/g, "''");
const content     = JSON.stringify(buildResult.jsonkb).replace(/'/g, "''");
const contentHash = buildResult.jsonkb.provenance.content_hash;
const query = "INSERT INTO jsonkb_store (entity_slug, entity_type, content, content_hash, updated_at) "
  + "VALUES ('" + slug + "', 'component', '" + content + "', '" + contentHash + "', NOW()) "
  + "ON CONFLICT (entity_slug, entity_type) DO UPDATE SET "
  + "content = EXCLUDED.content, content_hash = EXCLUDED.content_hash, updated_at = EXCLUDED.updated_at";
return [{ json: { query, entity_slug: buildResult.slug } }];
